import{c as i,Q as a,j as t,m as r}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"38. GitHub: Claude Code Ultimate Guide","description":"","frontmatter":{"url":"https://github.com/FlorianBruniaux/claude-code-ultimate-guide","status":"SUCCESS","date_fetched":"2026-05-18T00:00:00.000Z","repository":"FlorianBruniaux/claude-code-ultimate-guide"},"headers":[],"relativePath":"research/ai-articles/38-github-florian-claude-ultimate-guide.md","filePath":"research/ai-articles/38-github-florian-claude-ultimate-guide.md","lastUpdated":1779894392000}'),e={name:"research/ai-articles/38-github-florian-claude-ultimate-guide.md"};function o(n,l,s,u,d,g){return a(),t("div",null,[...l[0]||(l[0]=[r('<h1 id="_38-github-claude-code-ultimate-guide" tabindex="-1">38. GitHub: Claude Code Ultimate Guide <a class="header-anchor" href="#_38-github-claude-code-ultimate-guide" aria-label="Permalink to &quot;38. GitHub: Claude Code Ultimate Guide&quot;">​</a></h1><h2 id="核心摘要-繁體中文" tabindex="-1">核心摘要（繁體中文） <a class="header-anchor" href="#核心摘要-繁體中文" aria-label="Permalink to &quot;核心摘要（繁體中文）&quot;">​</a></h2><p>該儲存庫是關於 Claude Code 使用的全面教育資源，強調深度理解而非單純配置複製。包含 24,000+ 行參考文檔、48 個 Mermaid 圖表、271 道測驗題目和 181 個生產範本，特別強調安全性和威脅情報。</p><h3 id="核心特色" tabindex="-1">核心特色 <a class="header-anchor" href="#核心特色" aria-label="Permalink to &quot;核心特色&quot;">​</a></h3><p><strong>規模與深度</strong></p><ul><li><strong>24,000+ 行參考文檔</strong>：涵蓋架構、安全性和工作流程</li><li><strong>48 個 Mermaid 圖表</strong>：視覺化複雜概念</li><li><strong>271 道測驗題目</strong>：跨 9 個類別測試知識</li><li><strong>181 個生產範本</strong>：包括代理、命令、安全鉤子和技能</li></ul><p><strong>安全性強化（獨特價值）</strong></p><ul><li><strong>28 個 CVE 映射漏洞</strong>：系統性威脅追蹤</li><li><strong>655 個惡意技能資料庫</strong>：識別攻擊模式</li><li><strong>MCP 伺服器審計工作流程</strong>：驗證信任前使用</li><li><strong>生產加固指南</strong>：隔離、注入防禦和監控</li></ul><h3 id="學習路徑與結構" tabindex="-1">學習路徑與結構 <a class="header-anchor" href="#學習路徑與結構" aria-label="Permalink to &quot;學習路徑與結構&quot;">​</a></h3><p>根據用戶角色的結構化課程：</p><p><strong>初級開發者</strong>（7 步基礎路徑）</p><ul><li>Claude Code 基礎和架構</li><li>第一個代理和簡單工作流程</li><li>基本錯誤處理和除錯</li></ul><p><strong>資深開發者</strong>（6 步進階路徑）</p><ul><li>進階代理設計</li><li>多代理協調</li><li>性能優化和上下文管理</li></ul><p><strong>進階使用者</strong>（8 步完整掌握路徑）</p><ul><li>企業級架構設計</li><li>威脅建模和安全加固</li><li>MCP 開發和驗證</li><li>自訂工具鏈整合</li></ul><h3 id="五項黃金法則" tabindex="-1">五項黃金法則 <a class="header-anchor" href="#五項黃金法則" aria-label="Permalink to &quot;五項黃金法則&quot;">​</a></h3><ol><li><strong>驗證信任</strong>：Claude Code 產生的邏輯錯誤率較高，需要多層驗證</li><li><strong>審查 MCP</strong>：來自未知來源的伺服器存在安全風險</li><li><strong>管理上下文</strong>：70% 使用率時精度開始下降，性能衰退明顯</li><li><strong>漸進採用</strong>：從簡單開始，逐步擴展功能和複雜度</li><li><strong>使用方法論</strong>：TDD/SDD/BDD 對 AI 協作至關重要</li></ol><h3 id="開發方法論" tabindex="-1">開發方法論 <a class="header-anchor" href="#開發方法論" aria-label="Permalink to &quot;開發方法論&quot;">​</a></h3><p><strong>Test-Driven Development（TDD）</strong></p><ul><li>先寫測試，再實現代碼</li><li>AI 代理生成的代碼品質更高</li></ul><p><strong>Specification-Driven Development（SDD）</strong></p><ul><li>詳細規格優於含糊需求</li><li>規格應包含邊界條件和異常</li></ul><p><strong>Behavior-Driven Development（BDD）</strong></p><ul><li>用業務語言定義行為</li><li>便於 AI 理解上下文</li></ul><p><strong>Get Shit Done（GSD）方法</strong></p><ul><li>實用的務實方法</li><li>在時間緊張時選擇此方法</li></ul><h3 id="涵蓋的核心主題" tabindex="-1">涵蓋的核心主題 <a class="header-anchor" href="#涵蓋的核心主題" aria-label="Permalink to &quot;涵蓋的核心主題&quot;">​</a></h3><p><strong>架構與設計</strong></p><ul><li>Claude Code 內部機制</li><li>代理、技能和命令設計模式</li><li>上下文管理和記憶層次</li></ul><p><strong>安全與運維</strong></p><ul><li>威脅情報資料庫</li><li>MCP 伺服器審計工作流程</li><li>資料隱私和合規性</li><li>DevOps/SRE 模式</li><li>生產加固指南</li></ul><p><strong>進階功能</strong></p><ul><li>自訂代理和子代理</li><li>MCP 伺服器開發</li><li>多代理協調（Agent Teams）</li><li>鉤子和自動化</li><li>CI/CD 整合</li></ul><p><strong>知識驗證</strong></p><ul><li>271 題互動式測驗</li><li>分九個類別評估</li><li>跨基礎到進階級別</li></ul><h3 id="資源評估" tabindex="-1">資源評估 <a class="header-anchor" href="#資源評估" aria-label="Permalink to &quot;資源評估&quot;">​</a></h3><p>儲存庫包含 151 份資源評估，包括：</p><ul><li>證據分數</li><li>可信度評級</li><li>適用場景指引</li></ul><hr><h2 id="關鍵數據-引用" tabindex="-1">關鍵數據/引用 <a class="header-anchor" href="#關鍵數據-引用" aria-label="Permalink to &quot;關鍵數據/引用&quot;">​</a></h2><h3 id="規模統計" tabindex="-1">規模統計 <a class="header-anchor" href="#規模統計" aria-label="Permalink to &quot;規模統計&quot;">​</a></h3><ul><li><strong>24,000+</strong> 行參考文檔</li><li><strong>48</strong> 個 Mermaid 圖表</li><li><strong>271</strong> 道測驗題目</li><li><strong>181</strong> 個生產範本</li><li><strong>28</strong> 個 CVE 映射</li><li><strong>655</strong> 個惡意技能識別</li><li><strong>151</strong> 份資源評估</li></ul><h3 id="上下文管理關鍵閾值" tabindex="-1">上下文管理關鍵閾值 <a class="header-anchor" href="#上下文管理關鍵閾值" aria-label="Permalink to &quot;上下文管理關鍵閾值&quot;">​</a></h3><ul><li><strong>70%</strong> 使用率：精度開始下降</li><li><strong>80%</strong> 使用率：明顯性能衰退</li><li><strong>90%+</strong> 使用率：建議停止任務</li></ul><h3 id="驗證與信任原則" tabindex="-1">驗證與信任原則 <a class="header-anchor" href="#驗證與信任原則" aria-label="Permalink to &quot;驗證與信任原則&quot;">​</a></h3><blockquote><p>「驗證信任」——Claude Code 產生的邏輯錯誤率較高，需要系統性驗證步驟</p></blockquote><h3 id="mcp-審計流程" tabindex="-1">MCP 審計流程 <a class="header-anchor" href="#mcp-審計流程" aria-label="Permalink to &quot;MCP 審計流程&quot;">​</a></h3><ul><li>自動掃描已知惡意模式</li><li>沙箱隔離執行</li><li>權限最小化</li><li>事前審批機制</li></ul><hr><h2 id="獨特價值主張" tabindex="-1">獨特價值主張 <a class="header-anchor" href="#獨特價值主張" aria-label="Permalink to &quot;獨特價值主張&quot;">​</a></h2><p>此指南區別於其他資源的地方：</p><ol><li><strong>唯一全面威脅情報資料庫</strong>：655 個惡意技能識別</li><li><strong>系統性 MCP 安全審計方法</strong>：從 unknown source 驗證信任</li><li><strong>整合測試驅動開發</strong>：TDD/SDD/BDD 方法論</li><li><strong>證據基礎的資源評估</strong>：151 份有評分的資源</li><li><strong>角色差異化學習路徑</strong>：針對初級、資深和進階用戶</li></ol><hr><h2 id="訪問方式" tabindex="-1">訪問方式 <a class="header-anchor" href="#訪問方式" aria-label="Permalink to &quot;訪問方式&quot;">​</a></h2><ul><li><strong>網站</strong>：cc.bruniaux.com</li><li><strong>完整指南</strong>：guide/ultimate-guide.md</li><li><strong>MCP 伺服器</strong>：可集成到任何 Claude Code 工作階段</li><li><strong>互動式測驗</strong>：271 題知識驗證</li></ul><hr><h2 id="核心哲學" tabindex="-1">核心哲學 <a class="header-anchor" href="#核心哲學" aria-label="Permalink to &quot;核心哲學&quot;">​</a></h2><p>該指南著重於協助開發者從「複製配置」進展到「自信地設計客製化的代理工作流程」。強調深度理解而非單純工具使用，將 6 個月實務經驗濃縮為可行的知識。</p>',59)])])}const p=i(e,[["render",o]]);export{c as __pageData,p as default};
